    fbBuilder.addFloat64(6, _ATTITUDE_X);
    fbBuilder.addFloat64(7, _ATTITUDE_Y);
    fbBuilder.addFloat64(8, _ATTITUDE_Z);
    fbBuilder.addFloat64(9, _ATTITUDE_W);
    fbBuilder.addFloat64(10, _OMEGA_X);
    fbBuilder.addFloat64(11, _OMEGA_Y);
    fbBuilder.addFloat64(12, _OMEGA_Z);
    fbBuilder.addFloat64(13, _MASS);
    fbBuilder.addFloat64(14, _MASS_INITIAL);
    fbBuilder.addFloat64(15, _TARGET_POSITION_X);
    fbBuilder.addFloat64(16, _TARGET_POSITION_Y);
    fbBuilder.addFloat64(17, _TARGET_POSITION_Z);
    fbBuilder.addFloat64(18, _TARGET_VELOCITY_X);
    fbBuilder.addFloat64(19, _TARGET_VELOCITY_Y);
    fbBuilder.addFloat64(20, _TARGET_VELOCITY_Z);
    fbBuilder.addFloat64(21, _MISS_DISTANCE);
    fbBuilder.addOffset(22, SEEKEROffset);
    fbBuilder.addOffset(23, MOTOROffset);
    fbBuilder.addOffset(24, GUIDANCE_CMDOffset);
    fbBuilder.addUint8(25, _PHASE);
    fbBuilder.addUint8(26, _GUIDANCE_LAW);
    fbBuilder.addUint8(27, _TYPE);
    fbBuilder.addUint8(28, _ARMED);
    fbBuilder.addFloat32(29, _TIME_OF_FLIGHT);
    fbBuilder.addFloat32(30, _MAX_G);
    fbBuilder.addOffset(31, RESERVEDOffset);
    return fbBuilder.endTable();
  }

  /// Convenience method to serialize to byte list.
  @override
  Uint8List toBytes([String? fileIdentifier]) {
    final fbBuilder = fb.Builder(deduplicateTables: false);
    fbBuilder.finish(finish(fbBuilder), fileIdentifier);
    return fbBuilder.buffer;
  }
}
